import React, { useState, useRef, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Search, ShoppingBag, User, Menu, X, LogOut } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useCart } from '../../context/CartContext';
import { productAPI } from '../../api';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faShoppingBag } from '@fortawesome/free-solid-svg-icons';

import './Navbar.css';

export default function Navbar({ onMenuToggle }) {
  const { user, isAuthenticated, logout } = useAuth();
  const { cart } = useCart();
  const navigate = useNavigate();
  const [query, setQuery] = useState('');
  const [results, setResults] = useState([]);
  const [showResults, setShowResults] = useState(false);
  const [showUser, setShowUser] = useState(false);
  const searchRef = useRef();
  const userRef = useRef();
  const timer = useRef();

  useEffect(() => {
    const handler = (e) => {
      if (searchRef.current && !searchRef.current.contains(e.target)) setShowResults(false);
      if (userRef.current && !userRef.current.contains(e.target)) setShowUser(false);
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);

  const handleSearch = (val) => {
    setQuery(val);
    clearTimeout(timer.current);
    if (val.length < 2) { setResults([]); setShowResults(false); return; }
    timer.current = setTimeout(async () => {
      try {
        const res = await productAPI.search(val);
        setResults(res.data.data?.slice(0, 5) || []);
        setShowResults(true);
      } catch { setResults([]); }
    }, 300);
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (query.trim()) {
      navigate(`/products?q=${encodeURIComponent(query)}`);
      setShowResults(false);
    }
  };

  return (
    <nav className="navbar">
      <div className="nav-left">
        <button className="nav-menu-btn" onClick={onMenuToggle}><Menu size={22} /></button>
        <Link to="/" className="nav-logo">
          <FontAwesomeIcon icon={faShoppingBag} className="logo-icon" />
          <span className="logo-text">QualityProducts</span>
        </Link>
      </div>

      <form className="nav-search" onSubmit={handleSubmit} ref={searchRef}>
        <Search size={18} className="search-icon" />
        <input
          type="text" placeholder="Search products..."
          value={query} onChange={(e) => handleSearch(e.target.value)}
          onFocus={() => results.length > 0 && setShowResults(true)}
        />
        {query && <button type="button" className="search-clear" onClick={() => { setQuery(''); setResults([]); }}><X size={16} /></button>}
        {showResults && results.length > 0 && (
          <div className="search-dropdown">
            {results.map((p) => (
              <Link key={p.id} to={`/products/${p.id}`} className="search-result"
                onClick={() => { setShowResults(false); setQuery(''); }}>
                <img src={p.imageUrl} alt={p.name} />
                <div>
                  <span className="result-name">{p.name}</span>
                  <span className="result-price">${p.price}</span>
                </div>
              </Link>
            ))}
          </div>
        )}
      </form>

      <div className="nav-right">
        <Link to="/cart" className="nav-cart">
          <ShoppingBag size={22} />
          {cart.itemCount > 0 && <span className="cart-badge">{cart.itemCount}</span>}
        </Link>

        {isAuthenticated ? (
          <div className="nav-user" ref={userRef}>
            <button className="user-btn" onClick={() => setShowUser(!showUser)}>
              <div className="user-avatar">{user?.fullName?.[0] || 'U'}</div>
            </button>
            {showUser && (
              <div className="user-dropdown">
                <div className="user-info">
                  <div className="user-avatar-lg">{user?.fullName?.[0]}</div>
                  <div>
                    <p className="user-name">{user?.fullName}</p>
                    <p className="user-email">{user?.email}</p>
                  </div>
                </div>
                <div className="dropdown-divider" />
                <Link to="/account" className="dropdown-item" onClick={() => setShowUser(false)}>Account</Link>
                <Link to="/orders" className="dropdown-item" onClick={() => setShowUser(false)}>Orders</Link>
                <Link to="/settings" className="dropdown-item" onClick={() => setShowUser(false)}>Settings</Link>
                <div className="dropdown-divider" />
                <button className="dropdown-item logout" onClick={() => { logout(); setShowUser(false); navigate('/'); }}>
                  <LogOut size={16} /> Sign Out
                </button>
              </div>
            )}
          </div>
        ) : (
          <Link to="/login" className="btn btn-primary btn-sm">Sign In</Link>
        )}
      </div>
    </nav>
  );
}
